const fileName = $input.item.json.name;
const parentFolder = $input.item.json.parents?.[0] || '';
const fileId = $input.item.json.id;

// Remove file extension to get a clean name
const productName = fileName.replace(/\.[^/.]+$/, "").replace(/_/g, " ");

return {
  fileId: fileId,
  fileName: fileName,
  productName: productName,
  parentFolder: parentFolder,
  timestamp: new Date().toISOString()
};

const transcript = $input.item.json.candidates[0].content.parts[0].text;

return {
  originalTranscript: transcript,
  productName: $('Code in JavaScript').item.json.productName
};

const segments = $input.item.json;

// Groq returns segments array, combine all text
let fullTranscript = '';

// Handle both array and single segment response
if (Array.isArray($input.all())) {
  const allItems = $input.all();
  allItems.forEach(item => {
    if (item.json.text) {
      fullTranscript += item.json.text + ' ';
    }
  });
} else {
  fullTranscript = $input.item.json.text || '';
}

return {
  aiTranscript: fullTranscript.trim()
};

const geminiData = $input.first().json;
const groqData = $input.last().json;

return {
  productName: geminiData.productName,
  originalTranscript: geminiData.originalTranscript,
  aiTranscript: groqData.aiTranscript,
  mergedContext: `PRODUCT NAME: ${geminiData.productName}

=== ORIGINAL TRANSCRIPT (Gemini) ===
${geminiData.originalTranscript}

=== AI TRANSCRIPT (Groq Whisper) ===
${groqData.aiTranscript}`
};
